import React from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { ShoppingBag, Minus, Plus, Trash2 } from 'lucide-react';
import { useCart } from '../context/CartContext';

export default function CartPage() {
  const { cart, updateQuantity, removeItem, loading } = useCart();
  const navigate = useNavigate();

  if (loading) return <div className="page-loader"><div className="spinner" /></div>;

  if (!cart.items?.length) {
    return (
      <div className="page-container">
        <div className="cart-empty">
          <ShoppingBag size={56} color="var(--text-muted)" />
          <h2>Your cart is empty</h2>
          <p>Add some products to get started.</p>
          <Link to="/products" className="btn btn-primary">Browse Products</Link>
        </div>
      </div>
    );
  }

  return (
    <div className="page-container">
      <h1 className="page-title">Shopping Cart ({cart.itemCount} items)</h1>
      <div className="cart-layout">
        <div className="cart-items">
          {cart.items.map(item => (
            <div key={item.id} className="cart-item">
              <img src={item.product.imageUrl} alt={item.product.name} className="cart-item-img" />
              <div className="cart-item-info">
                <Link to={`/products/${item.product.id}`} className="cart-item-name" style={{ color: 'var(--text-primary)' }}>
                  {item.product.name}
                </Link>
                <p className="cart-item-meta">
                  {item.product.brand}
                  {item.selectedSize && ` • Size: ${item.selectedSize}`}
                  {item.selectedColor && ` • Color: ${item.selectedColor}`}
                </p>
                <div className="cart-item-bottom">
                  <div className="cart-qty">
                    <button onClick={() => updateQuantity(item.id, item.quantity - 1)}><Minus size={14} /></button>
                    <span>{item.quantity}</span>
                    <button onClick={() => updateQuantity(item.id, item.quantity + 1)}><Plus size={14} /></button>
                  </div>
                  <span className="cart-item-price">${item.lineTotal?.toFixed(2)}</span>
                </div>
                <button className="cart-remove" onClick={() => removeItem(item.id)}>
                  <Trash2 size={14} style={{ marginRight: 4 }} /> Remove
                </button>
              </div>
            </div>
          ))}
        </div>

        <div className="cart-summary">
          <h3>Order Summary</h3>
          <div className="summary-row"><span>Subtotal</span><span>${cart.subtotal?.toFixed(2)}</span></div>
          <div className="summary-row"><span>Tax</span><span>${cart.tax?.toFixed(2)}</span></div>
          <div className="summary-row"><span>Shipping</span><span>{cart.shipping > 0 ? `$${cart.shipping?.toFixed(2)}` : 'Free'}</span></div>
          <div className="summary-total"><span>Total</span><span>${cart.total?.toFixed(2)}</span></div>
          <button className="btn btn-primary btn-full btn-lg" onClick={() => navigate('/checkout')}>
            Proceed to Checkout
          </button>
          {cart.shipping > 0 && (
            <p style={{ fontSize: '0.78rem', color: 'var(--text-muted)', textAlign: 'center', marginTop: 12 }}>
              Add ${(50 - cart.subtotal).toFixed(2)} more for free shipping
            </p>
          )}
        </div>
      </div>
    </div>
  );
}
